    if st.button("🚀 Analyze MRI Scan", type="primary", use_container_width=True, key="det_run"):
        with st.spinner("🧠 Xception AI is analyzing your MRI scan..."):
            result = predict(image, model)
            if result is None:
                st.error("Prediction failed. Check the model file.")
                st.markdown("</div>", unsafe_allow_html=True)
                return

            st.markdown("---")
