# ═════════════════════════════════════════════════════════════════════════════
#  MAIN
# ═════════════════════════════════════════════════════════════════════════════
def main():
    _navbar()

    TAB_DEF = [
        ("home",      "🏠  Home"),
        ("detection", "🔬  Detection"),
        ("analysis",  "📊  Analysis"),
        ("neurobot",  "🤖  NeuroBot"),
    ]
    active = st.session_state.get("tab", "home")

    # Tab bar
    st.markdown("<div class='ns-tab-bar'>", unsafe_allow_html=True)
    cols = st.columns(len(TAB_DEF))
    for i, (tid, tlabel) in enumerate(TAB_DEF):
        with cols[i]:
            btn_type = "primary" if active == tid else "secondary"
            if st.button(tlabel, key=f"tab_{tid}", use_container_width=True, type=btn_type):
                st.session_state["tab"] = tid
                st.rerun()
    st.markdown("</div>", unsafe_allow_html=True)

    # Spacer for fixed nav elements
    st.markdown("<div class='ns-spacer'></div>", unsafe_allow_html=True)

    if active == "home":
        render_home()
    elif active == "detection":
        render_detection()
    elif active == "analysis":
        render_analysis()
    elif active == "neurobot":
        render_neurobot_page()


if __name__ == "__main__":
    main()